// @ts-check
import { defineConfig } from 'astro/config';
import react from '@astrojs/react';

// The Filigree member site deploys to the ROOT of its own subdomain (IA §1.3, §1.4):
//   site:  https://filigree.foundryside.dev
//   base:  '/'   (every member site is a domain root — no subpath gymnastics)
// Cross-subdomain links to other members are ABSOLUTE https://{member}.foundryside.dev
// URLs (generated by the shared @weft/site-kit data), so the site never hardcodes
// the roster and cannot drift from the hub.
export default defineConfig({
  site: 'https://filigree.foundryside.dev',
  base: '/',
  integrations: [react()],
});
